BEGIN TRANSACTION;
CREATE TABLE "P1_Identidad_Acceso_clinica" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(100) NOT NULL, "nit" varchar(20) NOT NULL UNIQUE, "direccion" text NOT NULL, "plan_suscripcion" varchar(50) NOT NULL, "email_contacto" varchar(254) NOT NULL, "logo" varchar(100) NULL, "telefono" varchar(20) NOT NULL, "fecha_creacion" datetime NOT NULL, "saldo" decimal NOT NULL);
CREATE TABLE "P1_Identidad_Acceso_dispositivomovil" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fcm_token" varchar(255) NOT NULL UNIQUE, "fecha_registro" datetime NOT NULL, "usuario_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P1_Identidad_Acceso_transaccionclinica" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "tipo" varchar(50) NOT NULL, "monto" decimal NOT NULL, "descripcion" text NOT NULL, "fecha" datetime NOT NULL, "metodo_pago" varchar(50) NOT NULL, "clinica_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_clinica" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P1_Identidad_Acceso_usuario" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "rol" varchar(20) NOT NULL, "clinica_id" bigint NULL REFERENCES "P1_Identidad_Acceso_clinica" ("id") DEFERRABLE INITIALLY DEFERRED, "especialidad" varchar(100) NOT NULL, "telefono" varchar(20) NOT NULL, "debe_cambiar_password" bool NOT NULL, "ultimo_cambio_password" datetime NOT NULL, "ci" varchar(20) NOT NULL);
CREATE TABLE "P1_Identidad_Acceso_usuario_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "usuario_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P1_Identidad_Acceso_usuario_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "usuario_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P2_Gestion_Clinica_evolucionclinica" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_sesion" datetime NOT NULL, "notas_sesion" text NOT NULL, "archivo_adjunto" varchar(100) NULL, "analisis_ia" text NOT NULL, "psicologo_id" bigint NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "historia_id" bigint NOT NULL REFERENCES "P2_Gestion_Clinica_historiaclinica" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P2_Gestion_Clinica_historiaclinica" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_creacion" datetime NOT NULL, "antecedentes_familiares" text NOT NULL, "antecedentes_personales" text NOT NULL, "diagnostico_preliminar" text NOT NULL, "paciente_id" bigint NOT NULL UNIQUE REFERENCES "P2_Gestion_Clinica_paciente" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P2_Gestion_Clinica_paciente" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nombre" varchar(100) NOT NULL, "ci" varchar(20) NOT NULL UNIQUE, "fecha_nacimiento" date NOT NULL, "telefono" varchar(20) NOT NULL, "motivo_consulta" text NULL, "clinica_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_clinica" ("id") DEFERRABLE INITIALLY DEFERRED, "fecha_registro" datetime NULL);
CREATE TABLE "P3_Logistica_Citas_cita" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_hora" datetime NOT NULL, "motivo" text NULL, "estado" varchar(20) NOT NULL, "paciente_id" bigint NOT NULL REFERENCES "P2_Gestion_Clinica_paciente" ("id") DEFERRABLE INITIALLY DEFERRED, "psicologo_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "duracion_minutos" integer unsigned NOT NULL CHECK ("duracion_minutos" >= 0), "monto" decimal NOT NULL, "estado_pago" varchar(20) NOT NULL, "metodo_pago" varchar(30) NOT NULL, "fecha_pago" datetime NULL, "fecha_cancelacion" datetime NULL, "motivo_cancelacion" varchar(255) NOT NULL, "cancelado_por_id" bigint NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P3_Logistica_Citas_listaespera" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fecha_registro" datetime NOT NULL, "paciente_id" bigint NOT NULL REFERENCES "P2_Gestion_Clinica_paciente" ("id") DEFERRABLE INITIALLY DEFERRED, "activo" bool NOT NULL, "observacion" text NOT NULL, "prioridad" integer NOT NULL);
CREATE TABLE "P4_IA_Administracion_comprobante" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nro_comprobante" varchar(50) NOT NULL UNIQUE, "pdf_archivo" varchar(100) NULL, "fecha_emision" datetime NOT NULL, "transaccion_id" bigint NOT NULL UNIQUE REFERENCES "P4_IA_Administracion_transaccion" ("id") DEFERRABLE INITIALLY DEFERRED, pdf_path varchar(100) NULL);
CREATE TABLE "P4_IA_Administracion_diagnosticoia" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "input_clinico" text NOT NULL, "resultado_ia" text NOT NULL, "probabilidad_acierto" real NOT NULL, "fecha_analisis" datetime NOT NULL, "psicologo_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "paciente_id" bigint NULL REFERENCES "P2_Gestion_Clinica_paciente" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "P4_IA_Administracion_logauditoria" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "accion" varchar(255) NOT NULL, "fecha" datetime NOT NULL, "usuario_id" bigint NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "clinica_id" bigint NULL REFERENCES "P1_Identidad_Acceso_clinica" ("id") DEFERRABLE INITIALLY DEFERRED, "ip_address" char(39) NULL, "user_agent" text NULL);
CREATE TABLE "P4_IA_Administracion_transaccion" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "monto" decimal NOT NULL, "fecha" datetime NOT NULL, "concepto" varchar(255) NOT NULL, "metodo_pago" varchar(20) NOT NULL, "clinica_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_clinica" ("id") DEFERRABLE INITIALLY DEFERRED, "paciente_id" bigint NOT NULL REFERENCES "P2_Gestion_Clinica_paciente" ("id") DEFERRABLE INITIALLY DEFERRED, tipo varchar(10) NOT NULL DEFAULT 'PAGO', descripcion varchar(255) NOT NULL DEFAULT '', cita_id bigint NULL);
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE "token_blacklist_blacklistedtoken" ("blacklisted_at" datetime NOT NULL, "token_id" bigint NOT NULL UNIQUE REFERENCES "token_blacklist_outstandingtoken" ("id") DEFERRABLE INITIALLY DEFERRED, "id" integer NOT NULL PRIMARY KEY AUTOINCREMENT);
CREATE TABLE "token_blacklist_outstandingtoken" ("token" text NOT NULL, "created_at" datetime NULL, "expires_at" datetime NOT NULL, "user_id" bigint NULL REFERENCES "P1_Identidad_Acceso_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "jti" varchar(255) NOT NULL UNIQUE, "id" integer NOT NULL PRIMARY KEY AUTOINCREMENT);
